import{A as e,M as t,k as n,n as r,r as i}from"./Container-AtTEkwmp.js";import{n as a}from"./Button-D1Ie1Ib0.js";import{t as o}from"./AnimatePresence-BoPar7o2.js";var s=a(`chevron-down`,[[`path`,{d:`m6 9 6 6 6-6`,key:`qrunsl`}]]),c=t(e(),1),l=n();function u({items:e,className:t}){let[n,a]=(0,c.useState)(null),u=e=>{a(n===e?null:e)};return(0,l.jsx)(`div`,{className:r(`space-y-3`,t),children:e.map((e,t)=>(0,l.jsxs)(`div`,{className:`rounded-lg border border-surface-200 bg-surface-100 overflow-hidden`,children:[(0,l.jsxs)(`button`,{onClick:()=>u(t),className:`flex w-full items-center justify-between p-5 text-left font-medium text-surface-900 hover:bg-surface-50 transition-colors cursor-pointer`,children:[(0,l.jsx)(`span`,{children:e.question}),(0,l.jsx)(i.div,{animate:{rotate:n===t?180:0},transition:{duration:.2},children:(0,l.jsx)(s,{className:`h-5 w-5 text-surface-500`})})]}),(0,l.jsx)(o,{initial:!1,children:n===t&&(0,l.jsx)(i.div,{initial:{height:0,opacity:0},animate:{height:`auto`,opacity:1},exit:{height:0,opacity:0},transition:{duration:.3,ease:[.22,1,.36,1]},children:(0,l.jsx)(`div`,{className:`px-5 pb-5 text-surface-600 leading-relaxed`,children:e.answer})})})]},t))})}var d=[{name:`Général`,items:[{question:`Qu'est-ce que PACIZZY ?`,answer:`PACIZZY est un logiciel SaaS (en ligne) conçu spécifiquement pour les artisans RGE. Il permet de générer des dossiers et devis conformes pour l'installation de pompes à chaleur, en automatisant les calculs, les formulaires et les exports.`},{question:`PACIZZY est-il adapté à mon activité ?`,answer:`PACIZZY est conçu pour tous les professionnels RGE qui installent des pompes à chaleur : artisans indépendants, petites équipes ou grandes entreprises. Que vous réalisiez 5 ou 50 installations par mois, PACIZZY s'adapte à votre volume.`},{question:`Faut-il installer un logiciel ?`,answer:`Non, PACIZZY est un logiciel 100% en ligne (SaaS). Vous y accédez depuis n'importe quel navigateur web, sur ordinateur, tablette ou smartphone. Aucune installation nécessaire.`},{question:`Mes données sont-elles sécurisées ?`,answer:`Absolument. Vos données sont hébergées en France sur des serveurs sécurisés et certifiés. Nous appliquons un chiffrement de bout en bout, des sauvegardes quotidiennes et sommes conformes au RGPD.`}]},{name:`Tarifs & Essai`,items:[{question:`L'essai gratuit est-il vraiment sans engagement ?`,answer:`Oui, l'essai gratuit de 1 mois est totalement sans engagement et sans carte bancaire requise. Vous avez accès à toutes les fonctionnalités pendant 30 jours.`},{question:`Puis-je changer de forfait à tout moment ?`,answer:`Oui, vous pouvez passer d'un forfait à l'autre à tout moment. L'upgrade est immédiat, et en cas de downgrade, le changement prend effet à la prochaine période de facturation.`},{question:`Y a-t-il des frais cachés ?`,answer:`Non, les prix affichés incluent toutes les fonctionnalités du forfait, les mises à jour et le support. Pas de surcoût par dossier ou par export.`},{question:`Proposez-vous des tarifs annuels ?`,answer:`Oui, nous proposons une réduction de 20% pour un engagement annuel. Contactez-nous pour en savoir plus.`}]},{name:`Fonctionnalités`,items:[{question:`Quels types de PAC sont supportés ?`,answer:`PACIZZY supporte tous les types de pompes à chaleur : air-eau, air-air, eau-eau, géothermiques. Les modèles de dossiers et de devis sont adaptés à chaque technologie.`},{question:`Les barèmes MaPrimeRénov' sont-ils à jour ?`,answer:`Oui, nos équipes mettent à jour les barèmes dès leur publication officielle par l'ANAH. Vous êtes assuré de toujours travailler avec les montants en vigueur.`},{question:`Puis-je personnaliser les devis avec mon logo ?`,answer:`Bien sûr ! Vous pouvez ajouter votre logo, vos coordonnées, vos conditions générales et personnaliser l'apparence de tous vos documents.`},{question:`PACIZZY gère-t-il les dossiers CEE ?`,answer:`Oui, PACIZZY génère les attestations et documents nécessaires pour les dossiers de Certificats d'Économies d'Énergie (CEE), en plus des dossiers MaPrimeRénov'.`}]},{name:`Support`,items:[{question:`Comment contacter le support ?`,answer:`Notre support est disponible par email à support@pacizzy.fr, par chat en direct depuis l'application, et par téléphone pour les forfaits Équipe et Entreprise.`},{question:`Proposez-vous des formations ?`,answer:`Oui, nous proposons des tutoriels en ligne gratuits, des webinaires mensuels pour le forfait Équipe, et des formations sur site personnalisées pour le forfait Entreprise.`},{question:`Quel est le délai de réponse du support ?`,answer:`Le délai moyen de réponse est de 2 heures en jours ouvrés. Les clients Équipe et Entreprise bénéficient d'un support prioritaire avec un délai garanti de 1 heure.`}]}];export{u as n,d as t};